mcqs.question:
What will be the output of the following code?
void display(int a=10, int b=20) {
 cout<<a<<" "<<b;
}
int main() {
 display(5);
 return 0;
}

What will be printed?
void test(int x, int y=10, int z=20) {
 cout<<x+y+z;
}
int main() {
 test(5, 15);
 return 0;
}

What is the output?
class Test {
public:
 void show(int a=5) { cout<<a; }
};
int main() {
 Test t;
 t.show();
 return 0;
}
